// ================================================================
// frontend/src/components/ChatWindow.js - REAL MESSAGES
// ================================================================

import React, { useState, useEffect, useRef } from 'react';
import { Send, ArrowLeft, Phone, Clock, Loader } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { mentorApi } from '../../services/mentorApi';
import './ChatWindow.css';

const ChatWindow = ({ mentor, onClose }) => {
  const { user } = useAuth();
  const [messages, setMessages] = useState([]);
  const [messageInput, setMessageInput] = useState('');
  const [loading, setLoading] = useState(true);
  const [sending, setSending] = useState(false);
  const messageEndRef = useRef(null);

  // Fetch messages on component mount
  useEffect(() => {
    if (mentor && mentor._id) {
      fetchRealMessages();
      // Poll for new messages every 2 seconds
      const interval = setInterval(fetchRealMessages, 2000);
      return () => clearInterval(interval);
    }
  }, [mentor._id]);

  // Auto scroll to bottom
  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const scrollToBottom = () => {
    messageEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  // Fetch REAL messages from database
  const fetchRealMessages = async () => {
    try {
      const data = await mentorApi.getMessages(mentor._id);
      setMessages(data || []);
      setLoading(false);
    } catch (error) {
      console.error('Error fetching messages:', error);
      setLoading(false);
    }
  };

  // Send REAL message
  const handleSendMessage = async () => {
    if (!messageInput.trim()) return;

    setSending(true);
    try {
      const newMessage = await mentorApi.sendMessage(
        mentor._id,
        messageInput,
        'text'
      );

      // Add to local state immediately
      setMessages([...messages, newMessage]);
      setMessageInput('');
    } catch (error) {
      console.error('Error sending message:', error);
      alert('Failed to send message. Please try again.');
    } finally {
      setSending(false);
    }
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey && !sending) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  if (loading) {
    return (
      <div className="chat-window">
        <div className="loading-center">
          <Loader className="spinner" size={40} />
          <p>Loading messages...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="chat-window">
      {/* Chat Header */}
      <div className="chat-header">
        <button onClick={onClose} className="btn-close-chat">
          <ArrowLeft size={20} />
        </button>

        <div className="header-info">
          <div className="mentor-info-header">
            <div className="avatar-small">{mentor.profileImage || '👤'}</div>
            <div>
              <h3>{mentor.name}</h3>
              <p className="company-info">{mentor.company} • {mentor.role}</p>
            </div>
          </div>

          <div className="header-actions">
            <div className="response-time">
              <Clock size={16} />
              <span>{mentor.responseTime}</span>
            </div>
          </div>
        </div>
      </div>

      {/* Messages Area */}
      <div className="chat-messages">
        {messages.length === 0 ? (
          <div className="empty-chat">
            <p>📝 No messages yet. Start the conversation!</p>
          </div>
        ) : (
          messages.map((msg, idx) => (
            <div
              key={msg._id || idx}
              className={`message-wrapper ${msg.sender === 'student' ? 'student' : 'mentor'}`}
            >
              {msg.sender === 'mentor' && (
                <div className="message-avatar">{mentor.profileImage || '👤'}</div>
              )}

              <div className="message-content">
                <div className={`message-bubble ${msg.sender}`}>
                  {msg.content}
                </div>
                <div className="message-time">
                  {new Date(msg.createdAt).toLocaleTimeString([], {
                    hour: '2-digit',
                    minute: '2-digit'
                  })}
                </div>
              </div>

              {msg.sender === 'student' && (
                <div className="message-avatar">👤 You</div>
              )}
            </div>
          ))
        )}
        <div ref={messageEndRef} />
      </div>

      {/* Message Input */}
      <div className="chat-input-area">
        <textarea
          value={messageInput}
          onChange={(e) => setMessageInput(e.target.value)}
          onKeyPress={handleKeyPress}
          placeholder="Ask your question... (Press Enter to send)"
          rows="1"
          disabled={sending}
        />
        <button
          onClick={handleSendMessage}
          disabled={!messageInput.trim() || sending}
          className="btn-send"
        >
          {sending ? <Loader size={20} className="spinner" /> : <Send size={20} />}
        </button>
      </div>
    </div>
  );
};

export default ChatWindow;
